import React, { useEffect, useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import './AuthPage.css';

function MailIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path
        d="M4 7.5A2.5 2.5 0 0 1 6.5 5h11A2.5 2.5 0 0 1 20 7.5v9a2.5 2.5 0 0 1-2.5 2.5h-11A2.5 2.5 0 0 1 4 16.5v-9z"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
      />
      <path
        d="M5 8l7 5 7-5"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function LockIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <rect
        x="5"
        y="10"
        width="14"
        height="10"
        rx="2.4"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
      />
      <path
        d="M8 10V8a4 4 0 1 1 8 0v2"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
        strokeLinecap="round"
      />
    </svg>
  );
}

export default function LoginPage() {
  const navigate = useNavigate();
  const { login, isLoggedIn } = useAuth();

  const [form, setForm] = useState({
    email: '',
    password: '',
    remember: true,
  });
  const [error, setError] = useState('');
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    if (isLoggedIn) {
      navigate('/dashboard', { replace: true });
    }
  }, [isLoggedIn, navigate]);

  const helperText = useMemo(() => {
    if (!form.email && !form.password) {
      return '토끼와 고양이 캐릭터가 먼저 반응하는 대화 화면으로 바로 이어져요.';
    }
    if (form.email && !form.password) {
      return '이제 비밀번호만 입력하면 바로 대화를 시작할 수 있어요.';
    }
    return '입력이 끝났어요. 로그인 후 대시보드와 대화 페이지로 이동할 수 있어요.';
  }, [form.email, form.password]);

  const updateField = (key, value) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const validate = () => {
    if (!form.email.trim()) return '이메일을 입력해주세요.';
    if (!/\S+@\S+\.\S+/.test(form.email)) return '올바른 이메일 형식을 입력해주세요.';
    if (!form.password.trim()) return '비밀번호를 입력해주세요.';
    if (form.password.length < 6) return '비밀번호는 6자 이상 입력해주세요.';
    return '';
  };

  const callLogin = async () => {
    if (typeof login !== 'function') {
      throw new Error('로그인 기능이 아직 연결되지 않았어요.');
    }

    if (login.length >= 2) {
      return login(form.email, form.password);
    }

    return login({
      email: form.email,
      password: form.password,
      remember: form.remember,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const nextError = validate();
    if (nextError) {
      setError(nextError);
      return;
    }

    setError('');
    setSubmitting(true);

    try {
      await callLogin();
      navigate('/dashboard', { replace: true });
    } catch (err) {
      setError(err?.message || '로그인 중 문제가 발생했어요. 다시 시도해주세요.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <section className="matey-auth">
      <div className="matey-auth__container">
        <div className="matey-auth__grid">
          <div className="matey-auth__visual">
            <div className="matey-auth__visual-card">
              <div className="matey-auth__visual-kicker">Welcome Back</div>

              <h1>
                다시 만나서 반가워요.
                <br />
                <strong>오늘 마음도 천천히 들어볼게요</strong>
              </h1>

              <p>
                단순 로그인 화면이 아니라, 대화로 이어지는 입구처럼 느껴지도록
                캐릭터와 안내 문구를 함께 배치했어요.
              </p>

              <div className="matey-auth__mascot-stage">
                <div className="matey-auth__mascot-stage-glow matey-auth__mascot-stage-glow--one" />
                <div className="matey-auth__mascot-stage-glow matey-auth__mascot-stage-glow--two" />

                <div className="matey-auth__mascot-image matey-auth__mascot-image--duo">
                  <img src="/images/rabbit-duo.png" alt="토끼와 고양이 캐릭터" />
                </div>

                <div className="matey-auth__bubble">
                  <strong>하루</strong>
                  <p>로그인하면 바로 오늘 감정 체크인과 캐릭터 대화를 이어갈 수 있어요.</p>
                </div>
              </div>

              <div className="matey-auth__tips">
                <span>대화 바로 시작</span>
                <span>감정 기록 이어보기</span>
                <span>리포트 확인</span>
              </div>
            </div>
          </div>

          <div className="matey-auth__form-shell">
            <div className="matey-auth__card">
              <div className="matey-auth__tabs">
                <Link to="/login" className="matey-auth__tab is-active">
                  로그인
                </Link>
                <Link to="/signup" className="matey-auth__tab">
                  회원가입
                </Link>
              </div>

              <div className="matey-auth__header">
                <span className="matey-auth__badge">Account Access</span>
                <h2>로그인</h2>
                <p>기존 계정으로 접속해서 대시보드와 캐릭터 대화를 계속 이어가세요.</p>
              </div>

              <form className="matey-auth__form" onSubmit={handleSubmit}>
                <label className="matey-auth__field">
                  <span>이메일</span>
                  <div className="matey-auth__input-wrap">
                    <i>
                      <MailIcon />
                    </i>
                    <input
                      type="email"
                      value={form.email}
                      onChange={(e) => updateField('email', e.target.value)}
                      placeholder="you@example.com"
                      autoComplete="email"
                    />
                  </div>
                </label>

                <label className="matey-auth__field">
                  <span>비밀번호</span>
                  <div className="matey-auth__input-wrap">
                    <i>
                      <LockIcon />
                    </i>
                    <input
                      type="password"
                      value={form.password}
                      onChange={(e) => updateField('password', e.target.value)}
                      placeholder="비밀번호를 입력해주세요"
                      autoComplete="current-password"
                    />
                  </div>
                </label>

                <div className="matey-auth__row">
                  <label className="matey-auth__check">
                    <input
                      type="checkbox"
                      checked={form.remember}
                      onChange={(e) => updateField('remember', e.target.checked)}
                    />
                    <span>로그인 상태 유지</span>
                  </label>

                  <Link to="/signup" className="matey-auth__text-link">
                    계정이 없나요?
                  </Link>
                </div>

                <div className="matey-auth__helper">
                  <strong>현재 안내</strong>
                  <p>{helperText}</p>
                </div>

                {error && <div className="matey-auth__error">{error}</div>}

                <button
                  type="submit"
                  className="matey-auth__submit"
                  disabled={submitting}
                >
                  {submitting ? '로그인 중...' : '로그인하고 시작하기'}
                </button>
              </form>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
